  1	import * as React from 'react';
  2	import {
  3	  FormGroup,
  4	  FormHelperText,
  5	  FormSection,
  6	  HelperText,
  7	  HelperTextItem,
  8	  TextInputTypes,
  9	} from '@patternfly/react-core';
 10	import { FormikProps, FormikValues, useFormikContext } from 'formik';
 11	import * as _ from 'lodash';
 12	import { useTranslation } from 'react-i18next';
 13	
 14	import { PAC_GH_APP_DOC, PAC_GH_APP_NEW } from './const';
 15	import PacPermissions from './PacPermissions';
 16	import { FlexForm, FormBody } from '../pipeline-builder/form-utils';
 17	import InputField from '../pipelines-details/multi-column-field/InputField';
 18	import { ExternalLink } from '../utils/link';
 19	import FormFooter from '../pipelines-details/multi-column-field/FormFooter';
 20	
 21	import './PacPage.scss';
 22	
 23	const PacAppForm: React.FC<FormikProps<FormikValues>> = ({
 24	  errors,
 25	  handleReset,
 26	  status,
 27	  isSubmitting,
 28	  values,
 29	}) => {
 30	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 31	  const { setStatus } = useFormikContext<FormikValues>();
 32	  const [manifestVal, setManifestVal] = React.useState<string>('');
 33	
 34	  const submitFrom = (event: React.FormEvent<EventTarget>) => {
 35	    if (!values.manifestData.hook_attributes.url) {
 36	      setStatus({
 37	        submitError: t('Unable to detect Event listener URL'),
 38	      });
 39	      event.preventDefault();
 40	    } else {
 41	      const dataMn = JSON.stringify({
 42	        ...values.manifestData,
 43	        name: values.applicationName,
 44	      });
 45	      setManifestVal(dataMn);
 46	    }
 47	  };
 48	  return (
 49	    <FlexForm
 50	      action={PAC_GH_APP_NEW}
 51	      onSubmit={submitFrom}
 52	      method="post"
 53	      data-test="form-setup-github-app"
 54	    >
 55	      <FormBody flexLayout className="opp-pac-form__body">
 56	        <FormSection className="pipelines-console-plugin__page-section-width">
 57	          <FormGroup
 58	            label={t('GitHub application name')}
 59	            isRequired
 60	            fieldId="app-name-field"
 61	          >
 62	            <InputField
 63	              type={TextInputTypes.text}
 64	              name="applicationName"
 65	              placeholder={t('Enter name of application')}
 66	              data-test="pac-applicationName"
 67	              required
 68	              aria-label={t('Enter name of application')}
 69	            />
 70	            <input
 71	              type="text"
 72	              name="manifest"
 73	              id="manifest"
 74	              value={manifestVal}
 75	              hidden
 76	            />
 77	
 78	            <FormHelperText>
 79	              <HelperText>
 80	                <HelperTextItem>
 81	                  {t(
 82	                    'Provide a unique name for your GitHub app, e.g. "pipelines-ci-clustername"',
 83	                  )}
 84	                </HelperTextItem>
 85	              </HelperText>
 86	            </FormHelperText>
 87	          </FormGroup>
 88	          <PacPermissions />
 89	          <ExternalLink
 90	            text={t('View all steps in documentation')}
 91	            href={PAC_GH_APP_DOC}
 92	          />
 93	        </FormSection>
 94	      </FormBody>
 95	      <FormFooter
 96	        handleReset={handleReset}
 97	        errorMessage={status && status.submitError}
 98	        isSubmitting={isSubmitting}
 99	        submitLabel={t('Setup')}
100	        disableSubmit={
101	          !_.isEmpty(errors) || isSubmitting || !!status?.submitError
102	        }
103	        resetLabel={t('Cancel')}
104	        sticky
105	      />
106	    </FlexForm>
107	  );
108	};
109	
110	export default PacAppForm;

